import type { TextStreamPart, UIMessage } from 'ai'
import { convertToModelMessages, stepCountIs, streamText } from 'ai'
import { AppEvents } from '../../lib/constants/app'
import {
  appendText,
  getLogPath,
  getSessionMetadataPath,
  getSessionPath,
  getSessionsDateDir,
  getWorkspaceSessionsDir,
  readdir,
  readJson,
  stat,
  writeJson,
} from '../../lib/path'
import type { SessionMetadata } from '../../lib/types/chat'
import { sendAppEvent } from '../window'
import type { AIProvider } from './factory'
import { getAIModel } from './factory'
import { createTools } from './tools'

export async function initAiFolders() {
  // Global sessions dir is no longer used; workspace-scoped init happens in initWorkspaceFolders
}

export async function initWorkspaceFolders(workspace: string) {
  const dir = getWorkspaceSessionsDir(workspace)
  const exists = await stat(dir).catch(() => null)
  if (!exists) {
    const fs = await import('node:fs/promises')
    await fs.mkdir(dir, { recursive: true })
  }
}

export async function saveSession(
  workspace: string,
  id: string,
  messages: UIMessage[],
  metadata?: SessionMetadata,
) {
  const path = getSessionPath(id, undefined, workspace)
  await writeJson(path, messages)

  if (metadata) {
    const metaPath = getSessionMetadataPath(id, undefined, workspace)
    const exists = await stat(metaPath).catch(() => null)
    if (!exists) {
      await writeJson(metaPath, metadata)
    }
  }

  sendAppEvent(AppEvents.SESSION_SAVED, id)
}

export async function loadSession(
  workspace: string,
  id: string,
  date?: string,
) {
  if (date) {
    const path = getSessionPath(id, date, workspace)
    return readJson(path).catch(() => null)
  }

  // Find session across all dates
  const dir = getWorkspaceSessionsDir(workspace)
  const dates = await readdir(dir).catch(() => [])
  for (const d of dates) {
    if (!d.isDirectory()) continue
    const dateDir = d.name
    const path = getSessionPath(id, dateDir, workspace)
    const content = await readJson(path).catch(() => null)
    if (content) return content
  }
  return null
}

export async function deleteSession(workspace: string, id: string) {
  const dir = getWorkspaceSessionsDir(workspace)
  const dates = await readdir(dir).catch(() => [])
  const { unlink } = await import('node:fs/promises')

  for (const d of dates) {
    if (!d.isDirectory()) continue
    const dateDir = d.name
    const path = getSessionPath(id, dateDir, workspace)
    const metaPath = getSessionMetadataPath(id, dateDir, workspace)

    if (await stat(path).catch(() => null)) {
      await unlink(path).catch(() => {})
      if (await stat(metaPath).catch(() => null)) {
        await unlink(metaPath).catch(() => {})
      }
    }
  }
}

export async function listSessions(workspace: string) {
  const dir = getWorkspaceSessionsDir(workspace)
  const dates = await readdir(dir).catch(() => [])
  const all: any[] = []
  for (const d of dates) {
    if (!d.isDirectory()) continue
    const date = d.name
    const dPath = getSessionsDateDir(date, workspace)
    const files = await readdir(dPath).catch(() => [])
    for (const f of files) {
      if (
        f.isFile() &&
        f.name.endsWith('.json') &&
        !f.name.endsWith('-metadata.json')
      ) {
        const id = f.name.replace('.json', '')
        const sessionPath = getSessionPath(id, date, workspace)
        const metaPath = getSessionMetadataPath(id, date, workspace)

        const [content, metadata, stats] = await Promise.all([
          readJson(sessionPath).catch(() => null),
          readJson(metaPath).catch(() => null),
          stat(sessionPath).catch(() => null),
        ])

        if (content && Array.isArray(content)) {
          const firstUser = content.find((m: any) => m.role === 'user')
          const preview =
            (firstUser as any)?.parts?.map((p: any) => p.text || '').join('') ||
            'No content'

          const title = metadata
            ? `${metadata.agentName} - ${metadata.modelName}`
            : `Session ${id.slice(-6)}`

          all.push({
            id,
            date,
            title,
            preview,
            lastModified:
              stats?.mtime.toISOString() || new Date().toISOString(),
            messageCount: content.length,
          })
        }
      }
    }
  }

  // De-duplicate by id, keeping the most recent one
  const unique = new Map<string, any>()
  for (const s of all) {
    const existing = unique.get(s.id)
    if (!existing || s.lastModified > existing.lastModified) {
      unique.set(s.id, s)
    }
  }

  return Array.from(unique.values()).sort((a, b) =>
    b.lastModified.localeCompare(a.lastModified),
  )
}

export async function aiChat({
  messages,
  config,
  workspaceFolders,
  activeFile,
}: {
  messages: UIMessage[]
  config: AIProvider & { enabledTools?: Record<string, boolean> }
  workspaceFolders: string[]
  activeFile?: string
}) {
  const requestId = Math.random().toString(36).slice(2, 10)
  const model = getAIModel(config)
  try {
    const toolContext = {
      workspaceFolders,
      activeFile,
    }
    const cachedTools = createTools(toolContext)
    console.log('[AI Chat] Context initialized:', toolContext)

    const enabledTools: Record<string, any> = {}
    const toolSettings = config.enabledTools || {}

    Object.keys(cachedTools).forEach((toolName) => {
      if (toolSettings[toolName] !== false) {
        enabledTools[toolName] = cachedTools[toolName]
      }
    })

    const emit = (part: TextStreamPart<any>) => {
      sendAppEvent(AppEvents.AI_CHAT_DELTA, { requestId, part })
    }

    // Extract system message and convert to model messages
    const systemMessage = messages.find((m) => m.role === 'system')
    const chatMessages = messages.filter((m) => m.role !== 'system')
    const modelMessages = await convertToModelMessages(chatMessages, {
      tools: enabledTools,
    })

    const system = systemMessage
      ? systemMessage.parts
          .filter((p): p is { type: 'text'; text: string } => p.type === 'text')
          .map((p) => p.text)
          .join('\n')
      : undefined

    ;(async () => {
      try {
        const result = streamText({
          model,
          system,
          messages: modelMessages,
          tools: enabledTools,
          stopWhen: stepCountIs(10),
        })

        let fullResponseText = ''
        let reasoningText = ''
        const fullToolCalls: any[] = []

        for await (const part of result.fullStream) {
          switch (part.type) {
            case 'text-delta':
              fullResponseText += part.text
              emit(part)
              break
            case 'reasoning-delta':
              reasoningText += part.text
              emit(part)
              break
            case 'tool-input-delta':
              emit(part)
              break
            case 'tool-call':
              fullToolCalls.push(part)
              emit(part)
              break
            case 'tool-result':
              emit(part)
              break
            case 'finish-step':
            case 'finish':
            case 'error':
            case 'start':
              emit(part)
              break
          }
        }

        console.log(
          `[AI] Full Response [${requestId}]:`,
          JSON.stringify(
            {
              text: fullResponseText,
              reasoning: reasoningText,
              toolCalls: fullToolCalls,
            },
            null,
            2,
          ),
        )

        const logPath = getLogPath()
        const logEntry = `[${new Date().toISOString()}] AI Response: ${fullResponseText.slice(0, 100)}...\n`
        await appendText(logPath, logEntry).catch(() => {})
      } catch (err: any) {
        console.error('[AI Chat Stream Error]', err)
        emit({ type: 'error', error: err.message || String(err) })
      }
    })()

    return { requestId }
  } catch (error: any) {
    console.error('[AI Chat Error]', error)
    throw error
  }
}

import type { UIMessage } from 'ai'

export function genId(): string {
  return `msg_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`
}

/**
 * Helper to get text content from a UIMessage for copying/exporting.
 */
export function getMessageText(msg: UIMessage): string {
  const role = msg.role.toUpperCase()
  const parts = msg.parts || []
  const content = parts
    .map((p) => {
      switch (p.type) {
        case 'text':
          return p.text
        case 'reasoning':
          return `\n[Thinking]\n${p.text}\n`
        case 'dynamic-tool': {
          const name = p.toolName || 'tool'
          const input = p.input
            ? `\nInput: ${typeof p.input === 'string' ? p.input : JSON.stringify(p.input, null, 2)}`
            : ''
          const output = p.output ? `\nOutput:\n${p.output}` : ''
          return `\n[Tool: ${name}${p.state ? ` (${p.state})` : ''}]${input}${output}\n`
        }
        default:
          return ''
      }
    })
    .join('\n')

  return `[${role}]\n${content.trim()}`
}

export function appendToAssistant(
  prev: UIMessage[],
  text: string,
): UIMessage[] {
  const last = prev[prev.length - 1]
  if (last && last.role === 'assistant') {
    const parts = [...last.parts]
    const lastPart = parts[parts.length - 1]
    if (lastPart && lastPart.type === 'text') {
      const idx = parts.length - 1
      parts[idx] = { ...lastPart, text: lastPart.text + text }
    } else {
      parts.push({ type: 'text', text, state: 'streaming' })
    }
    return [...prev.slice(0, -1), { ...last, parts }]
  }

  return [
    ...prev,
    {
      id: genId(),
      role: 'assistant',
      parts: [{ type: 'text', text, state: 'streaming' }],
    },
  ]
}

export function appendReasoningToAssistant(
  prev: UIMessage[],
  reasoning: string,
): UIMessage[] {
  const last = prev[prev.length - 1]
  if (last && last.role === 'assistant') {
    const parts = [...last.parts]
    const lastPart = parts[parts.length - 1]
    if (lastPart && lastPart.type === 'reasoning') {
      const idx = parts.length - 1
      parts[idx] = { ...lastPart, text: lastPart.text + reasoning }
    } else {
      parts.push({ type: 'reasoning', text: reasoning, state: 'streaming' })
    }
    return [...prev.slice(0, -1), { ...last, parts }]
  }

  return [
    ...prev,
    {
      id: genId(),
      role: 'assistant',
      parts: [{ type: 'reasoning', text: reasoning, state: 'streaming' }],
    },
  ]
}

export function appendPartToAssistant(
  prev: UIMessage[],
  part: { toolCallId: string; toolName: string; input?: unknown },
): UIMessage[] {
  const last = prev[prev.length - 1]
  if (last && last.role === 'assistant') {
    const parts = [...last.parts]

    // Check if we already have this tool call
    const existingIdx = parts.findIndex(
      (p) => p.type === 'dynamic-tool' && p.toolCallId === part.toolCallId,
    )

    if (existingIdx !== -1) {
      parts[existingIdx] = {
        ...parts[existingIdx],
        state: 'input-available',
        input: part.input,
      } as any
    } else {
      parts.push({
        type: 'dynamic-tool',
        toolCallId: part.toolCallId,
        toolName: part.toolName,
        state: 'input-available',
        input: part.input,
      } as any)
    }

    return [...prev.slice(0, -1), { ...last, parts }]
  }

  return [
    ...prev,
    {
      id: genId(),
      role: 'assistant',
      parts: [
        {
          type: 'dynamic-tool',
          toolCallId: part.toolCallId,
          toolName: part.toolName,
          state: 'input-available',
          input: part.input,
        } as any,
      ],
    },
  ]
}

export function updateToolResult(
  prev: UIMessage[],
  part: { toolCallId: string; toolName: string; output?: unknown },
): UIMessage[] {
  // Find the last assistant message that contains a matching dynamic-tool part
  for (let i = prev.length - 1; i >= 0; i--) {
    const msg = prev[i]
    if (msg.role !== 'assistant') continue

    const parts = [...msg.parts]
    const idx = parts.findIndex(
      (p) => p.type === 'dynamic-tool' && p.toolCallId === part.toolCallId,
    )

    if (idx !== -1) {
      parts[idx] = {
        ...parts[idx],
        state: 'output-available',
        output: part.output,
      } as any
      return [...prev.slice(0, i), { ...msg, parts }, ...prev.slice(i + 1)]
    }
  }

  // Fallback: no matching tool call found, append as new assistant message
  return [
    ...prev,
    {
      id: genId(),
      role: 'assistant',
      parts: [
        {
          type: 'dynamic-tool',
          toolCallId: part.toolCallId,
          toolName: part.toolName,
          state: 'output-available',
          input: undefined,
          output: part.output,
        } as any,
      ],
    },
  ]
}

export function appendToolInputDeltaToAssistant(
  prev: UIMessage[],
  id: string,
  delta: string,
): UIMessage[] {
  const last = prev[prev.length - 1]
  if (last && last.role === 'assistant') {
    const parts = [...last.parts]
    const idx = parts.findIndex(
      (p) => p.type === 'dynamic-tool' && p.toolCallId === id,
    )

    if (idx !== -1) {
      const p = parts[idx] as any
      const currentInput =
        typeof p.input === 'string' ? p.input : JSON.stringify(p.input || '')
      parts[idx] = {
        ...p,
        input: currentInput + delta,
        state: 'input-streaming',
      } as any
      return [...prev.slice(0, -1), { ...last, parts }]
    }
  }
  return prev
}

export const isErrorMessage = (content: any) => {
  if (!content) return false
  const c =
    typeof content === 'string' ? content.trim() : JSON.stringify(content)
  return (
    c.startsWith('Error:') ||
    c.startsWith('Execution Error:') ||
    c.startsWith('**') ||
    c.includes('"status": "error"')
  )
}

export function findUnfulfilledToolCalls(messages: UIMessage[]): any[] {
  const allCalls: any[] = []

  for (const m of messages) {
    for (const p of m.parts) {
      if (p.type === 'dynamic-tool') {
        if (p.state === 'input-available' || p.state === 'input-streaming') {
          allCalls.push(p)
        } else if (p.state === 'output-available') {
          const idx = allCalls.findIndex((c) => c.toolCallId === p.toolCallId)
          if (idx !== -1) allCalls.splice(idx, 1)
        }
      }
    }
  }

  return allCalls
}

import type { TextStreamPart, UIMessage } from 'ai'
import { useCallback, useEffect, useRef, useState } from 'react'
import { AppEvents } from '../../../../lib/constants/app'
import { DEFAULT_SETTINGS } from '../../../../lib/constants/settings'
import type { SettingsState } from '../../../shared/lib/types'
import { useAppEventSubscriber } from '../../../views/ViewContext'
import type { ChatInputHandle } from '../components/InputEditor'
import { type AgentLoopConfig, runAgentLoop } from '../utils/agent'
import { executeCommandOnly } from '../utils/commands'
import {
  appendPartToAssistant,
  appendReasoningToAssistant,
  appendToAssistant,
  appendToolInputDeltaToAssistant,
  genId,
  updateToolResult,
} from '../utils/message'

// import { MOCK_MESSAGES } from '../utils/mocks'

export function useAIChat() {
  const subscribeToAppEvents = useAppEventSubscriber()
  const [settings, setSettings] = useState<SettingsState>(
    DEFAULT_SETTINGS as SettingsState,
  )
  const [activeTabPath, setActiveTabPath] = useState<string>('')
  const [workspaceFolders, setWorkspaceFolders] = useState<string[]>([])
  const [messages, setMessages] = useState<UIMessage[]>([])
  // const [messages, setMessages] = useState<UIMessage[]>(MOCK_MESSAGES)
  const [sessionId, setSessionId] = useState<string | null>(null)
  const [loading, setLoading] = useState(false)
  const [currentStep, setCurrentStep] = useState<TextStreamPart<any> | null>(
    null,
  )
  const [error, setError] = useState<{
    message: string
    redacted: string
  } | null>(null)

  const inputRef = useRef<ChatInputHandle>(null)
  const abortRef = useRef<AbortController | null>(null)
  const loadingRef = useRef(loading)

  const [artifactStatus, setArtifactStatus] = useState<{
    memory: { exists: boolean; path: string }
    task: { exists: boolean; path: string }
    plan: { exists: boolean; path: string }
  } | null>(null)

  const loadArtifactStatus = useCallback(async () => {
    const status = await window.aynite.getArtifactsStatus()
    setArtifactStatus(status)
  }, [])

  useEffect(() => {
    loadArtifactStatus()
  }, [loadArtifactStatus])

  useEffect(() => {
    loadingRef.current = loading
  }, [loading])

  const loadSettings = useCallback(async () => {
    try {
      const [resAI, resAgents, resTools, resPrompts] = await Promise.all([
        window.aynite.getConfig('ai'),
        window.aynite.getConfig('agents'),
        window.aynite.getConfig('tools'),
        window.aynite.getConfig('prompts'),
      ])
      setSettings((prev) => ({
        ...prev,
        ai: resAI || prev.ai,
        agents: resAgents || prev.agents,
        aiTools: resTools?.active || prev.aiTools,
        prompts: resPrompts || prev.prompts,
      }))
    } catch (_e) {}
  }, [])

  const loadWorkspaceFolders = useCallback(async () => {
    const folders = await window.aynite.getWorkspaceFolders()
    if (folders) setWorkspaceFolders(folders)
  }, [])

  const loadSessions = useCallback(async () => {
    const res = await window.aynite.listSessions()
    return res || []
  }, [])

  const approvalIdRef = useRef<string | null>(null)
  const [pendingApproval, setPendingApproval] = useState<{
    command: string
    cwd: string
  } | null>(null)

  useEffect(() => {
    loadSettings()
    loadWorkspaceFolders()
  }, [loadSettings, loadWorkspaceFolders])

  useAppEventSubscriber()((event) => {
    if (event.type === 'config-changed') loadSettings()
    if (event.type === 'workspace-changed') loadWorkspaceFolders()
    if (event.type === 'active-tab-changed') setActiveTabPath(event.data.path)
    if (event.type === AppEvents.ACTIVE_SESSION_CHANGED) {
      const { id } = event.data as { id: string }
      window.aynite.loadSession(id).then((res: any) => {
        if (res) {
          setMessages(res)
          setSessionId(id)
        }
      })
    }
    if (event.type === AppEvents.AI_APPROVAL_REQUEST) {
      const { id, command, cwd } = event.data as any
      approvalIdRef.current = id
      setPendingApproval({ command, cwd })
    }
  })

  useEffect(() => {
    const loadInitialSession = async () => {
      const activeSessionId = await window.aynite.getConfig('activeSessionId')
      if (activeSessionId) {
        const res = await window.aynite.loadSession(activeSessionId)
        if (res) {
          setMessages(res)
          setSessionId(activeSessionId)
        }
      }
    }

    loadInitialSession()
  }, [])

  useEffect(() => {
    if (messages.length > 0 && !sessionId) {
      const newId = Date.now().toString()
      setSessionId(newId)
      window.aynite.setConfig('activeSessionId', newId)
    }
  }, [messages, sessionId])

  useEffect(() => {
    if (sessionId && messages.length > 0) {
      const timer = setTimeout(async () => {
        try {
          const activeId = settingsRef.current.ai?.activeId
          const activeProvider =
            settingsRef.current.ai?.providers?.find((p) => p.id === activeId) ||
            settingsRef.current.ai?.providers?.[0]

          const activeAgent = settingsRef.current.agents?.list?.find(
            (a) => a.id === settingsRef.current.agents?.activeId,
          )

          const metadata = {
            agentName: activeAgent?.name || 'Chat',
            modelName: activeProvider?.name || activeProvider?.model || 'AI',
            createdAt: new Date().toISOString(),
            updatedAt: new Date().toISOString(),
          }

          await window.aynite.saveSession(sessionId, messages, metadata)
        } catch (_err) {}
      }, 1000)
      return () => clearTimeout(timer)
    }
    return undefined
  }, [messages, sessionId])

  const handleApprove = useCallback(() => {
    if (approvalIdRef.current) {
      window.aynite.respondToAiApproval(approvalIdRef.current, true)
      approvalIdRef.current = null
    }
    setPendingApproval(null)
  }, [])

  const handleReject = useCallback(() => {
    if (approvalIdRef.current) {
      window.aynite.respondToAiApproval(approvalIdRef.current, false)
      approvalIdRef.current = null
    }
    setPendingApproval(null)
  }, [])

  const settingsRef = useRef(settings)
  useEffect(() => {
    settingsRef.current = settings
  }, [settings])

  const messagesRef = useRef(messages)
  useEffect(() => {
    messagesRef.current = messages
  }, [messages])

  const workspaceFoldersRef = useRef(workspaceFolders)
  useEffect(() => {
    workspaceFoldersRef.current = workspaceFolders
  }, [workspaceFolders])

  const activeTabPathRef = useRef(activeTabPath)
  useEffect(() => {
    activeTabPathRef.current = activeTabPath
  }, [activeTabPath])

  const sendMessage = useCallback(
    async (text: string) => {
      if (!text.trim() || loadingRef.current) return
      setError(null)

      const commandMentionRegex = />cmd\[(.*?)\]\((.*?)\)/g
      const skillMentionRegex = /\/skill\[(.*?)\]\((.*?)\)/g

      if (
        await executeCommandOnly(
          text,
          activeTabPathRef.current,
          messagesRef.current,
          setMessages,
          setLoading,
        )
      )
        return

      const commandMatches = [...text.matchAll(commandMentionRegex)]
      const commandResults: {
        name: string
        stdout: string
        stderr: string
        error?: string
      }[] = []

      if (commandMatches.length > 0) {
        setLoading(true)
        for (const match of commandMatches) {
          const [_full, name, path] = match
          try {
            const res = await window.aynite.runDirectCommand({
              commandPath: path,
              params: [],
              currentFile: activeTabPathRef.current,
            })
            commandResults.push({
              name,
              stdout: res.stdout || '',
              stderr: res.stderr || '',
            })
          } catch (e: unknown) {
            const errorMsg = e instanceof Error ? e.message : String(e)
            commandResults.push({
              name,
              stdout: '',
              stderr: errorMsg,
              error: errorMsg,
            })
          }
        }
        setLoading(false)
      }

      const activeId = settingsRef.current.ai?.activeId
      const activeProvider =
        settingsRef.current.ai?.providers?.find((p) => p.id === activeId) ||
        settingsRef.current.ai?.providers?.[0]

      const activeAgent = settingsRef.current.agents?.list?.find(
        (a) => a.id === settingsRef.current.agents?.activeId,
      )
      const agentPromptFiles = activeAgent?.promptFiles || []

      const agentConfig: AgentLoopConfig = {
        id: activeProvider?.id || 'chat',
        name: activeProvider?.name || 'Chat',
        provider: activeProvider?.provider || 'ollama',
        apiKey: activeProvider?.apiKey || '',
        baseUrl: activeProvider?.baseUrl || '',
        model: activeProvider?.model || '',
        compatibility: activeProvider?.compatibility,
        enabledTools: settingsRef.current.aiTools,
        agentPromptFiles,
      }

      // Build command results text inline (no separate commandResults field)
      let resultsText = ''
      for (const res of commandResults) {
        const content = [res.stdout, res.stderr]
          .filter(Boolean)
          .join('\n')
          .trim()
        const result =
          content || (res.error ? `Error: ${res.error}` : '(No output)')
        resultsText += `> Command: ${res.name}\n${result}\n\n---\n\n`
      }

      const initialMessages = [...messagesRef.current]
      if (initialMessages.length === 0) {
        const globalPromptFiles = settingsRef.current.prompts?.files || []
        const systemPrompt = await window.aynite.getMergedSystemPrompt(
          globalPromptFiles,
          agentPromptFiles,
        )
        if (systemPrompt) {
          initialMessages.push({
            id: genId(),
            role: 'system',
            parts: [{ type: 'text', text: systemPrompt }],
          })
        }
      }

      // Create user message with command results inlined as text
      const userText = resultsText
        ? `${text}\n\nI ran local commands, here are the results:\n\n${resultsText}`
        : text

      const userMsg: UIMessage = {
        id: genId(),
        role: 'user',
        parts: [{ type: 'text', text: userText }],
      }

      const updatedMessages = [...initialMessages, userMsg]
      setMessages(updatedMessages)
      setLoading(true)

      const cleanText = text
        .replace(skillMentionRegex, '')
        .replace(commandMentionRegex, '')
        .trim()

      if (!cleanText && commandMatches.length > 0) {
        setLoading(false)
        return
      }

      const abort = new AbortController()
      abortRef.current = abort

      try {
        const resultHistory = await runAgentLoop(
          updatedMessages,
          agentConfig,
          workspaceFoldersRef.current,
          (event: TextStreamPart<any>) => {
            setCurrentStep(event)
            switch (event.type) {
              case 'text-delta':
                setMessages((prev) => appendToAssistant(prev, event.text))
                break
              case 'reasoning-delta':
                setMessages((prev) =>
                  appendReasoningToAssistant(prev, event.text),
                )
                break
              case 'tool-input-delta':
                setMessages((prev) =>
                  appendToolInputDeltaToAssistant(prev, event.id, event.delta),
                )
                break
              case 'tool-call':
                setMessages((prev) =>
                  appendPartToAssistant(prev, {
                    toolCallId: event.toolCallId,
                    toolName: event.toolName,
                    input: event.input,
                  }),
                )
                break
              case 'tool-result':
                setMessages((prev) =>
                  updateToolResult(prev, {
                    toolCallId: event.toolCallId,
                    toolName: event.toolName,
                    output: event.output,
                  }),
                )
                loadArtifactStatus()
                break
              case 'error':
                setError({
                  message: String(event.error),
                  redacted: String(event.error).includes('fetch failed')
                    ? 'Connection failed. Please check if your AI provider service is running.'
                    : String(event.error).includes('401') ||
                        String(event.error).includes('invalid_api_key')
                      ? 'Authentication failed. Please check your API key.'
                      : 'An error occurred while communicating with the AI provider.',
                })
                break
              case 'finish':
                setCurrentStep(null)
                break
            }
          },
          activeTabPathRef.current,
          abort.signal,
          subscribeToAppEvents,
        )
        setMessages(resultHistory)
      } catch (e: unknown) {
        const msg = e instanceof Error ? e.message : String(e)
        setError({
          message: msg,
          redacted:
            'A system error occurred. Please check your configuration and try again.',
        })
      } finally {
        setLoading(false)
        setCurrentStep(null)
        abortRef.current = null
      }
    },
    [subscribeToAppEvents, loadArtifactStatus],
  )

  const clearChat = useCallback(() => {
    setMessages([])
    setSessionId(null)
    abortRef.current?.abort()
  }, [])

  const copyToClipboard = useCallback((text: string) => {
    window.aynite
      .writeClipboard(text)
      .catch((err) => console.error('[useAIChat] Failed to copy', err))
  }, [])

  const revertToMessage = useCallback((index: number) => {
    setMessages((prev) => {
      if (index < 0 || index >= prev.length) return prev
      return prev.slice(0, index + 1)
    })
  }, [])

  const switchAgent = useCallback(async (agentId: string) => {
    await window.aynite.setConfig('agents', { activeId: agentId })
  }, [])

  const switchProvider = useCallback(
    async (providerId: string) => {
      await window.aynite.setConfig('ai', { activeId: providerId })
      loadArtifactStatus()
    },
    [loadArtifactStatus],
  )

  // Simple token estimator: (chars / 4) * 1.1
  const tokenCount = messages.reduce((acc, m) => {
    const text = m.parts.map((p) => (p.type === 'text' ? p.text : '')).join('')
    return acc + Math.ceil((text.length / 4) * 1.1)
  }, 0)

  return {
    settings,
    messages,
    loading,
    currentStep,
    pendingApproval,
    workspaceFolders,
    inputRef,
    abortRef,
    handleApprove,
    handleReject,
    sendMessage,
    clearChat,
    loadSessions,
    setMessages,
    setSessionId,
    copyToClipboard,
    revertToMessage,
    switchAgent,
    switchProvider,
    error,
    setError,
    artifactStatus,
    loadArtifactStatus,
    tokenCount,
  }
}

import type { AgentLoopConfig } from '../../../../lib/types/ai'

export type { AgentLoopConfig }

import type { TextStreamPart, UIMessage } from 'ai'
import { genId } from './message'

export async function runAgentLoop(
  messages: UIMessage[],
  config: AgentLoopConfig,
  workspaceFolders: string[],
  onEvent: (event: TextStreamPart<any>) => void,
  activeFile: string,
  abortSignal: AbortSignal,
  subscribe: (handler: (event: any) => void) => () => void,
): Promise<UIMessage[]> {
  const loopMessages: UIMessage[] = []
  let reasoningAccum = ''
  let textAccum = ''

  // Track all tool calls in this loop to preserve their inputs for results
  const allToolCalls = new Map<string, any>()
  // Current step's tool calls for the next assistant message
  let currentStepToolCalls: any[] = []

  const flushAssistant = () => {
    if (textAccum || reasoningAccum || currentStepToolCalls.length > 0) {
      const parts: any[] = []

      if (reasoningAccum) {
        parts.push({ type: 'reasoning', text: reasoningAccum, state: 'done' })
      }

      if (textAccum) {
        parts.push({ type: 'text', text: textAccum, state: 'done' })
      }

      if (currentStepToolCalls.length > 0) {
        currentStepToolCalls.forEach((tc) => {
          parts.push({
            type: 'dynamic-tool',
            toolCallId: tc.toolCallId,
            toolName: tc.toolName,
            state: 'input-available',
            input: tc.input || tc.args,
          } as any)
        })
      }

      loopMessages.push({
        id: genId(),
        role: 'assistant',
        parts,
      })
      textAccum = ''
      reasoningAccum = ''
      currentStepToolCalls = []
    }
  }

  return new Promise((fulfill, reject) => {
    window.aynite
      .aiChat({
        messages: [...messages, ...loopMessages],
        config: {
          id: 'temp',
          name: 'Temp',
          provider: config.provider,
          baseUrl: config.baseUrl,
          apiKey: config.apiKey,
          model: config.model,
          compatibility: config.compatibility,
          enabledTools: config.enabledTools,
        },
        workspaceFolders,
        activeFile,
      })
      .then((res: { requestId?: string }) => {
        const requestId = res.requestId
        if (!requestId) {
          fulfill([...messages, ...loopMessages])
          return
        }
        const unsubscribe = subscribe(async (event: any) => {
          if (
            event.type !== 'ai-chat-delta' ||
            event.data.requestId !== requestId
          )
            return
          if (abortSignal.aborted) {
            unsubscribe()
            fulfill([...messages, ...loopMessages])
            return
          }

          const part = event.data.part as TextStreamPart<any>
          switch (part.type) {
            case 'text-delta':
              textAccum += part.text
              onEvent(part)
              break

            case 'reasoning-delta':
              reasoningAccum += part.text
              onEvent(part)
              break

            case 'tool-input-delta':
              onEvent(part)
              break

            case 'tool-call': {
              allToolCalls.set(part.toolCallId, part)
              const existingIdx = currentStepToolCalls.findIndex(
                (tc) => tc.toolCallId === part.toolCallId,
              )
              if (existingIdx !== -1) {
                currentStepToolCalls[existingIdx] = part
              } else {
                currentStepToolCalls.push(part)
              }
              onEvent(part)
              break
            }

            case 'tool-result': {
              const matchingCall = allToolCalls.get(part.toolCallId)
              const _input = matchingCall?.input || matchingCall?.args || {}

              flushAssistant()

              // Update the matching dynamic-tool part in the last assistant message
              if (loopMessages.length > 0) {
                const last = loopMessages[loopMessages.length - 1]
                const parts = [...last.parts]
                const idx = parts.findIndex(
                  (p) =>
                    p.type === 'dynamic-tool' &&
                    p.toolCallId === part.toolCallId,
                )
                if (idx !== -1) {
                  parts[idx] = {
                    ...parts[idx],
                    state: 'output-available',
                    output: part.output,
                  } as any
                  loopMessages[loopMessages.length - 1] = { ...last, parts }
                }
              }

              onEvent(part)
              break
            }

            case 'finish-step':
              onEvent(part)
              break

            case 'error': {
              unsubscribe()
              flushAssistant()
              onEvent(part)
              fulfill([...messages, ...loopMessages])
              break
            }

            case 'finish':
              unsubscribe()
              flushAssistant()
              onEvent({ type: 'finish' } as any)
              fulfill([...messages, ...loopMessages])
              break
          }
        })

        abortSignal.addEventListener('abort', () => {
          unsubscribe()
          fulfill([...messages, ...loopMessages])
        })
      })
      .catch((err: any) => {
        reject(err)
      })
  })
}

import type { TextStreamPart, UIMessage } from 'ai'
import { convertToModelMessages, stepCountIs, streamText } from 'ai'
import { AppEvents } from '../../lib/constants/app'
import {
  appendText,
  getLogPath,
  getSessionMetadataPath,
  getSessionPath,
  getSessionsDateDir,
  getWorkspaceSessionsDir,
  readdir,
  readJson,
  stat,
  writeJson,
} from '../../lib/path'
import type { SessionMetadata } from '../../lib/types/chat'
import { sendAppEvent } from '../window'
import type { AIProvider } from './factory'
import { getAIModel } from './factory'
import { createTools } from './tools'

export async function initAiFolders() {
  // Global sessions dir is no longer used; workspace-scoped init happens in initWorkspaceFolders
}

export async function initWorkspaceFolders(workspace: string) {
  const dir = getWorkspaceSessionsDir(workspace)
  const exists = await stat(dir).catch(() => null)
  if (!exists) {
    const fs = await import('node:fs/promises')
    await fs.mkdir(dir, { recursive: true })
  }
}

export async function saveSession(
  workspace: string,
  id: string,
  messages: UIMessage[],
  metadata?: SessionMetadata,
) {
  const path = getSessionPath(id, undefined, workspace)
  await writeJson(path, messages)

  if (metadata) {
    const metaPath = getSessionMetadataPath(id, undefined, workspace)
    const exists = await stat(metaPath).catch(() => null)
    if (!exists) {
      await writeJson(metaPath, metadata)
    }
  }

  sendAppEvent(AppEvents.SESSION_SAVED, id)
}

export async function loadSession(
  workspace: string,
  id: string,
  date?: string,
) {
  if (date) {
    const path = getSessionPath(id, date, workspace)
    return readJson(path).catch(() => null)
  }

  // Find session across all dates
  const dir = getWorkspaceSessionsDir(workspace)
  const dates = await readdir(dir).catch(() => [])
  for (const d of dates) {
    if (!d.isDirectory()) continue
    const dateDir = d.name
    const path = getSessionPath(id, dateDir, workspace)
    const content = await readJson(path).catch(() => null)
    if (content) return content
  }
  return null
}

export async function deleteSession(workspace: string, id: string) {
  const dir = getWorkspaceSessionsDir(workspace)
  const dates = await readdir(dir).catch(() => [])
  const { unlink } = await import('node:fs/promises')

  for (const d of dates) {
    if (!d.isDirectory()) continue
    const dateDir = d.name
    const path = getSessionPath(id, dateDir, workspace)
    const metaPath = getSessionMetadataPath(id, dateDir, workspace)

    if (await stat(path).catch(() => null)) {
      await unlink(path).catch(() => {})
      if (await stat(metaPath).catch(() => null)) {
        await unlink(metaPath).catch(() => {})
      }
    }
  }
}

export async function listSessions(workspace: string) {
  const dir = getWorkspaceSessionsDir(workspace)
  const dates = await readdir(dir).catch(() => [])
  const all: any[] = []
  for (const d of dates) {
    if (!d.isDirectory()) continue
    const date = d.name
    const dPath = getSessionsDateDir(date, workspace)
    const files = await readdir(dPath).catch(() => [])
    for (const f of files) {
      if (
        f.isFile() &&
        f.name.endsWith('.json') &&
        !f.name.endsWith('-metadata.json')
      ) {
        const id = f.name.replace('.json', '')
        const sessionPath = getSessionPath(id, date, workspace)
        const metaPath = getSessionMetadataPath(id, date, workspace)

        const [content, metadata, stats] = await Promise.all([
          readJson(sessionPath).catch(() => null),
          readJson(metaPath).catch(() => null),
          stat(sessionPath).catch(() => null),
        ])

        if (content && Array.isArray(content)) {
          const firstUser = content.find((m: any) => m.role === 'user')
          const preview =
            (firstUser as any)?.parts?.map((p: any) => p.text || '').join('') ||
            'No content'

          const title = metadata
            ? `${metadata.agentName} - ${metadata.modelName}`
            : `Session ${id.slice(-6)}`

          all.push({
            id,
            date,
            title,
            preview,
            lastModified:
              stats?.mtime.toISOString() || new Date().toISOString(),
            messageCount: content.length,
          })
        }
      }
    }
  }

  // De-duplicate by id, keeping the most recent one
  const unique = new Map<string, any>()
  for (const s of all) {
    const existing = unique.get(s.id)
    if (!existing || s.lastModified > existing.lastModified) {
      unique.set(s.id, s)
    }
  }

  return Array.from(unique.values()).sort((a, b) =>
    b.lastModified.localeCompare(a.lastModified),
  )
}

export async function aiChat({
  messages,
  config,
  workspaceFolders,
  activeFile,
}: {
  messages: UIMessage[]
  config: AIProvider & { enabledTools?: Record<string, boolean> }
  workspaceFolders: string[]
  activeFile?: string
}) {
  const requestId = Math.random().toString(36).slice(2, 10)
  const model = getAIModel(config)
  try {
    const toolContext = {
      workspaceFolders,
      activeFile,
    }
    const cachedTools = createTools(toolContext)
    console.log('[AI Chat] Context initialized:', toolContext)

    const enabledTools: Record<string, any> = {}
    const toolSettings = config.enabledTools || {}

    Object.keys(cachedTools).forEach((toolName) => {
      if (toolSettings[toolName] !== false) {
        enabledTools[toolName] = cachedTools[toolName]
      }
    })

    const emit = (part: TextStreamPart<any>) => {
      sendAppEvent(AppEvents.AI_CHAT_DELTA, { requestId, part })
    }

    // Extract system message and convert to model messages
    const systemMessage = messages.find((m) => m.role === 'system')
    const chatMessages = messages.filter((m) => m.role !== 'system')
    const modelMessages = await convertToModelMessages(chatMessages, {
      tools: enabledTools,
    })

    const system = systemMessage
      ? systemMessage.parts
          .filter((p): p is { type: 'text'; text: string } => p.type === 'text')
          .map((p) => p.text)
          .join('\n')
      : undefined

    ;(async () => {
      try {
        const result = streamText({
          model,
          system,
          messages: modelMessages,
          tools: enabledTools,
          stopWhen: stepCountIs(10),
        })

        let fullResponseText = ''
        let reasoningText = ''
        const fullToolCalls: any[] = []

        for await (const part of result.fullStream) {
          switch (part.type) {
            case 'text-delta':
              fullResponseText += part.text
              emit(part)
              break
            case 'reasoning-delta':
              reasoningText += part.text
              emit(part)
              break
            case 'tool-input-delta':
              emit(part)
              break
            case 'tool-call':
              fullToolCalls.push(part)
              emit(part)
              break
            case 'tool-result':
              emit(part)
              break
            case 'finish-step':
            case 'finish':
            case 'error':
            case 'start':
              emit(part)
              break
          }
        }

        console.log(
          `[AI] Full Response [${requestId}]:`,
          JSON.stringify(
            {
              text: fullResponseText,
              reasoning: reasoningText,
              toolCalls: fullToolCalls,
            },
            null,
            2,
          ),
        )

        const logPath = getLogPath()
        const logEntry = `[${new Date().toISOString()}] AI Response: ${fullResponseText.slice(0, 100)}...\n`
        await appendText(logPath, logEntry).catch(() => {})
      } catch (err: any) {
        console.error('[AI Chat Stream Error]', err)
        emit({ type: 'error', error: err.message || String(err) })
      }
    })()

    return { requestId }
  } catch (error: any) {
    console.error('[AI Chat Error]', error)
    throw error
  }
}

