    }
    setPendingApproval(null)
  }, [])

  const handleReject = useCallback(() => {
    if (approvalIdRef.current) {
      window.aynite.respondToAiApproval(approvalIdRef.current, false)
      approvalIdRef.current = null
    }
    setPendingApproval(null)
  }, [])

  const settingsRef = useRef(settings)
  useEffect(() => {
    settingsRef.current = settings
  }, [settings])

  const messagesRef = useRef(messages)
  useEffect(() => {
    messagesRef.current = messages
  }, [messages])

  const workspaceFoldersRef = useRef(workspaceFolders)
  useEffect(() => {
    workspaceFoldersRef.current = workspaceFolders
  }, [workspaceFolders])

  const activeTabPathRef = useRef(activeTabPath)
  useEffect(() => {
    activeTabPathRef.current = activeTabPath
  }, [activeTabPath])

  const sendMessage = useCallback(
    async (text: string) => {
      if (!text.trim() || loadingRef.current) return
      setError(null)

      const commandMentionRegex = />cmd\[(.*?)\]\((.*?)\)/g
      const skillMentionRegex = /\/skill\[(.*?)\]\((.*?)\)/g

      if (
        await executeCommandOnly(
          text,
          activeTabPathRef.current,
          messagesRef.current,
          setMessages,
          setLoading,
        )
      )
        return

      const commandMatches = [...text.matchAll(commandMentionRegex)]
      const commandResults: {
        name: string
        stdout: string
        stderr: string
        error?: string
      }[] = []

      if (commandMatches.length > 0) {
        setLoading(true)
        for (const match of commandMatches) {
          const [_full, name, path] = match
          try {
            const res = await window.aynite.runDirectCommand({
              commandPath: path,
              params: [],
              currentFile: activeTabPathRef.current,
            })
            commandResults.push({
              name,
              stdout: res.stdout || '',
              stderr: res.stderr || '',
            })
          } catch (e: unknown) {
            const errorMsg = e instanceof Error ? e.message : String(e)
            commandResults.push({
              name,
              stdout: '',
              stderr: errorMsg,
              error: errorMsg,
            })
          }
        }
        setLoading(false)
      }

      const activeId = settingsRef.current.ai?.activeId
      const activeProvider =
        settingsRef.current.ai?.providers?.find((p) => p.id === activeId) ||
        settingsRef.current.ai?.providers?.[0]

      const activeAgent = settingsRef.current.agents?.list?.find(
        (a) => a.id === settingsRef.current.agents?.activeId,
      )
      const agentPromptFiles = activeAgent?.promptFiles || []

      const agentConfig: AgentLoopConfig = {
        id: activeProvider?.id || 'chat',
        name: activeProvider?.name || 'Chat',
        provider: activeProvider?.provider || 'ollama',
        apiKey: activeProvider?.apiKey || '',
        baseUrl: activeProvider?.baseUrl || '',
        model: activeProvider?.model || '',
        compatibility: activeProvider?.compatibility,
        enabledTools: settingsRef.current.aiTools,
        agentPromptFiles,
      }

      // Build command results text inline (no separate commandResults field)
      let resultsText = ''
      for (const res of commandResults) {
        const content = [res.stdout, res.stderr]
          .filter(Boolean)
          .join('\n')
          .trim()
        const result =
          content || (res.error ? `Error: ${res.error}` : '(No output)')
        resultsText += `> Command: ${res.name}\n${result}\n\n---\n\n`
      }

      const initialMessages = [...messagesRef.current]
      if (initialMessages.length === 0) {
        const globalPromptFiles = settingsRef.current.prompts?.files || []
        const systemPrompt = await window.aynite.getMergedSystemPrompt(
          globalPromptFiles,
          agentPromptFiles,
        )
        if (systemPrompt) {
          initialMessages.push({
            id: genId(),
            role: 'system',
            parts: [{ type: 'text', text: systemPrompt }],
          })
        }
      }

      // Create user message with command results inlined as text
      const userText = resultsText
        ? `${text}\n\nI ran local commands, here are the results:\n\n${resultsText}`
        : text

      const userMsg: UIMessage = {
        id: genId(),
        role: 'user',
        parts: [{ type: 'text', text: userText }],
      }

      const updatedMessages = [...initialMessages, userMsg]
      setMessages(updatedMessages)
      setLoading(true)

      const cleanText = text
        .replace(skillMentionRegex, '')
        .replace(commandMentionRegex, '')
        .trim()

      if (!cleanText && commandMatches.length > 0) {
        setLoading(false)
        return
      }

      const abort = new AbortController()
      abortRef.current = abort

      try {
        const resultHistory = await runAgentLoop(
          updatedMessages,
          agentConfig,
          workspaceFoldersRef.current,
          (event: TextStreamPart<any>) => {
            setCurrentStep(event)
            switch (event.type) {
              case 'text-delta':
                setMessages((prev) => appendToAssistant(prev, event.text))
                break
              case 'reasoning-delta':
                setMessages((prev) =>
                  appendReasoningToAssistant(prev, event.text),
                )
                break
              case 'tool-input-delta':
                setMessages((prev) =>
                  appendToolInputDeltaToAssistant(prev, event.id, event.delta),
                )
                break
              case 'tool-call':
                setMessages((prev) =>
                  appendPartToAssistant(prev, {
                    toolCallId: event.toolCallId,
                    toolName: event.toolName,
                    input: event.input,
                  }),
                )
                break
              case 'tool-result':
                setMessages((prev) =>
                  updateToolResult(prev, {
                    toolCallId: event.toolCallId,
                    toolName: event.toolName,
                    output: event.output,
                  }),
                )
                loadArtifactStatus()
                break
              case 'error':
                setError({
                  message: String(event.error),
                  redacted: String(event.error).includes('fetch failed')
                    ? 'Connection failed. Please check if your AI provider service is running.'
                    : String(event.error).includes('401') ||
                        String(event.error).includes('invalid_api_key')
                      ? 'Authentication failed. Please check your API key.'
                      : 'An error occurred while communicating with the AI provider.',
                })
                break
              case 'finish':
                setCurrentStep(null)
                break
            }
          },
          activeTabPathRef.current,
          abort.signal,
          subscribeToAppEvents,
        )
        setMessages(resultHistory)
      } catch (e: unknown) {
        const msg = e instanceof Error ? e.message : String(e)
        setError({
          message: msg,
          redacted:
            'A system error occurred. Please check your configuration and try again.',
        })
      } finally {
        setLoading(false)
        setCurrentStep(null)
        abortRef.current = null
      }
    },
    [subscribeToAppEvents, loadArtifactStatus],
  )

  const clearChat = useCallback(() => {
    setMessages([])
    setSessionId(null)
    abortRef.current?.abort()
  }, [])

  const copyToClipboard = useCallback((text: string) => {
    window.aynite
      .writeClipboard(text)
      .catch((err) => console.error('[useAIChat] Failed to copy', err))
  }, [])

  const revertToMessage = useCallback((index: number) => {
    setMessages((prev) => {
      if (index < 0 || index >= prev.length) return prev
      return prev.slice(0, index + 1)
    })
  }, [])

  const switchAgent = useCallback(async (agentId: string) => {
    await window.aynite.setConfig('agents', { activeId: agentId })
  }, [])

  const switchProvider = useCallback(
    async (providerId: string) => {
      await window.aynite.setConfig('ai', { activeId: providerId })
      loadArtifactStatus()
    },
    [loadArtifactStatus],
  )

  // Simple token estimator: (chars / 4) * 1.1
  const tokenCount = messages.reduce((acc, m) => {
    const text = m.parts.map((p) => (p.type === 'text' ? p.text : '')).join('')
    return acc + Math.ceil((text.length / 4) * 1.1)
  }, 0)

  return {
    settings,
    messages,
    loading,
    currentStep,
    pendingApproval,
    workspaceFolders,
    inputRef,
    abortRef,
    handleApprove,
    handleReject,
    sendMessage,
    clearChat,
    loadSessions,
    setMessages,
    setSessionId,
    copyToClipboard,
    revertToMessage,
    switchAgent,
    switchProvider,
    error,
    setError,
    artifactStatus,
    loadArtifactStatus,
    tokenCount,
  }
}

import {
  AlertCircle,
  Brain,
  ClipboardList,
  FileCode,
  Layers,
  X,
} from 'lucide-react'
import { forwardRef } from 'react'
import { Button } from '../../../shared/basic/Button'
import { SelectionMenu } from '../../../shared/featured/SelectionMenu'
import { useAppOperation } from '../../ViewContext'
import { type ChatInputHandle, InputEditor } from './InputEditor'

interface InputAreaProps {
  loading: boolean
  onSend: (text: string) => void
  onAbort: () => void
  onClear: () => void
  workspaceFolders: string[]
  getAllFiles: () => Promise<any>
  getAvailableSkills: () => Promise<any>
  getAvailableCommands: () => Promise<any>
  error: { message: string; redacted: string } | null
  setError: (err: { message: string; redacted: string } | null) => void
  artifactStatus: {
    memory: { exists: boolean; path: string }
    task: { exists: boolean; path: string }
    plan: { exists: boolean; path: string }
  } | null
  tokenCount: number
}

export const InputArea = forwardRef<ChatInputHandle, InputAreaProps>(
  (
    {
      loading,
      onSend,
      onAbort,
      onClear,
      workspaceFolders,
      getAllFiles,
      getAvailableSkills,
      getAvailableCommands,
      error,
      setError,
      artifactStatus,
      tokenCount,
    },
    ref,
  ) => {
    const executeOperation = useAppOperation()

    const artifactItems = [
      {
        id: artifactStatus?.memory?.path || 'memory',
        label: artifactStatus?.memory?.exists ? 'memory.md' : 'Not initialized',
        subtitle: 'Project Memory',
        icon: <Brain size={14} />,
        disabled: !artifactStatus?.memory?.exists,
      },
      {
        id: artifactStatus?.plan?.path || 'plan',
        label: artifactStatus?.plan?.exists
          ? 'implementation_plan.md'
          : 'Not proposed',
        subtitle: 'Implementation Plan',
        icon: <FileCode size={14} />,
        disabled: !artifactStatus?.plan?.exists,
      },
      {
        id: artifactStatus?.task?.path || 'task',
        label: artifactStatus?.task?.exists ? 'task.md' : 'Not created',
        subtitle: 'Task List',
        icon: <ClipboardList size={14} />,
        disabled: !artifactStatus?.task?.exists,
      },
    ]

    const onSelectArtifact = (path: string) => {
      if (path?.includes('/')) {
        executeOperation('SWITCH_FILE', { path })
      }
    }

    const formatNumber = (num: number) => {
      if (num >= 1000000000) return `${(num / 1000000000).toFixed(1)}B`
      if (num >= 1000000) return `${(num / 1000000).toFixed(1)}M`
      if (num >= 1000) return `${(num / 1000).toFixed(1)}K`
      return num.toString()
    }

    return (
      <div className="absolute bottom-0 left-0 right-0 px-12 pb-10 bg-gradient-to-t from-background via-background to-transparent z-layout pointer-events-none">
        <div className="max-w-[900px] mx-auto relative group pointer-events-auto">
          <div className="flex items-center justify-between px-2 mb-2 animate-in fade-in slide-in-from-bottom-1 duration-500">
            <div className="flex items-center gap-2">
              <SelectionMenu
                items={artifactItems}
                onSelect={onSelectArtifact}
                side="top"
                trigger={
                  <Button
                    variant="ghost"
                    className="text-muted-foreground/30 hover:text-primary transition-colors focus:outline-none p-0 h-auto font-bold uppercase tracking-widest text-[9px] hover:bg-transparent flex items-center gap-1.5"
                  >
                    <Layers size={13} />
                    Artifacts
                  </Button>
                }
                title="Project Artifacts"
              />
            </div>

            {tokenCount > 0 && (
              <div
                className="flex items-center gap-1.5 px-2 py-0.5 rounded-full bg-foreground/[0.02] border border-border/5 text-[9px] font-bold uppercase tracking-wider text-muted-foreground/40 cursor-help transition-all hover:bg-foreground/[0.04] hover:text-muted-foreground/60"
                title={`Estimated context tokens used in this session: ${tokenCount.toLocaleString()}`}
              >
                <div className="w-1 h-1 rounded-full bg-primary/30 animate-pulse" />
                {formatNumber(tokenCount)} tokens
              </div>
            )}
          </div>

          {error && (
            <div className="mb-3 p-3 rounded-xl bg-destructive/10 border border-destructive/20 flex items-start gap-3 animate-in fade-in slide-in-from-bottom-2 shadow-xl backdrop-blur-md">
              <AlertCircle className="w-4 h-4 text-destructive shrink-0 mt-0.5" />
              <div className="flex-1 space-y-1">
                <p className="text-[10px] font-bold uppercase tracking-wider text-destructive/80">
                  AI Stream Error
                </p>
                <p className="text-xs text-foreground/90 leading-relaxed font-medium">
                  {error.redacted}
                </p>
                <Button
                  variant="ghost"
                  onClick={() => executeOperation('SETTINGS', { tab: 'ai' })}
                  className="text-[11px] font-bold text-primary hover:text-primary/80 transition-colors mt-1 p-0 h-auto inline-flex"
                >
                  Update AI Provider Settings →
                </Button>
              </div>
              <Button
                variant="ghost"
                size="icon"
                onClick={() => setError(null)}
                className="text-muted-foreground/40 hover:text-foreground transition-colors p-1"
              >
                <X size={14} />
              </Button>
            </div>
          )}
          <InputEditor
            ref={ref}
            placeholder="Type your message or use / for skills..."
            onSend={onSend}
            loading={loading}
            onAbort={onAbort}
            onClear={onClear}
            workspaceFolders={workspaceFolders}
            getAllFiles={getAllFiles}
            getAvailableSkills={getAvailableSkills}
            getAvailableCommands={getAvailableCommands}
          />
        </div>
      </div>
    )
  },
)

InputArea.displayName = 'InputArea'

